var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어때요, 박스 군? 자기가 만든 캐릭터가 움직이는 소감은?","JPN":"どうかな？　ダンボール君。自分で作ったキャラクターが動く感想は。","ENG":"So, Box. How does it feel to see your creation brought to life?","TWN":"怎麼樣，紙箱小朋友？看到自己製作的角色動起來，感覺如何？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……이런 건 처음이에요.","JPN":"……こんなのは初めてです。","ENG":"...I never experienced anything like this before.","TWN":"……我第一次有這種感覺。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그동안 항상 저 혼자서만 그림 그리고 겨우 인터넷에 올리는 게 전부였는데…….","JPN":"今まではいつも僕一人で描いて、ネットに投稿するだけでしたけど……","ENG":"All I ever did was to draw by myself and post them on the internet...","TWN":"過去我都是自己一個人畫畫，頂多就是上傳到網路上……"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"모두의 힘을 합해서 캐릭터를 움직이게 하는 거 정말 즐거운 것 같아요!","JPN":"みんな力を合わせてキャラを動かせるのって、本当に楽しいです！","ENG":"It feels great to team up and put it all together!","TWN":"像這樣大家一起同心合力讓角色動起來，真的好熱血！"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그렇죠? 좋은 게임을 만들기 위해서는 먼저 개발자 스스로가 즐거워야 한다고 생각하거든요.","JPN":"はは、そうだろう？　いいゲームを作るためには、まず開発者が楽しくないとね。","ENG":"Ha ha, it does. Good games are made when the developers are actually having fun.","TWN":"哈哈，是吧？我認為自己必須先樂在其中，才能夠製作出好遊戲。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 혹시 괜찮다면, 한 가지 더 제안을 드리고 싶네요.","JPN":"それでなんだが、よければもう一つ提案したい。","ENG":"If it’s okay with you, I’d like to propose another offer.","TWN":"所以你不介意的話，我想再跟你商量一下。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"박스 군, 저희 학생들과 함께 게임을 제작해보는 건 어떨까요?","JPN":"ダンボール君、私の生徒と共にゲームを制作してみないか？","ENG":"Would you like to be a part of our team, Box?","TWN":"紙箱小朋友，你要試著和我的學生們一起製作遊戲嗎？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마 박스 군에게도 잊지 못할 소중한 경험이 될 겁니다.","JPN":"多分、ダンボール君にも忘れられない大事な経験になると思うんだ。","ENG":"I think it’ll be an invaluable experience for you as well.","TWN":"我相信這對你而言會成為一個難忘的寶貴經驗。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네!? 제가 게임 제작이요!?","JPN":"はい！？　僕が、ゲーム制作を！？","ENG":"Me?! In the team?!","TWN":"真的嗎？我要製作遊戲嗎！？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와, 대단해! 박스 군의 실력이라면 우리 다음 코미페까지 카운터즈 사가를 완성할 수 있을지도 몰라!","JPN":"わあ、すごい！　ダンボール君の腕も加われば、私たち次のコミフェまでカウンターズ・サーガを完成できるかもしれない！","ENG":"Yes! With your artistry, we might be able to finish Counters Saga by next year’s Comic Festival!","TWN":"哇，好厲害喔！有你加入的話，說不定可以在下一屆動漫展前完成制裁者傳奇欸！"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하고 싶은 걸지도…… 코미페 완판.","JPN":"やりたいかも……コミフェ、完売。","ENG":"To be sold out at Comic Festival… Maybe we want.","TWN":"有點想……動漫展完售。"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 그게 좋네!","JPN":"へへっ、それええな！","ENG":"Heh, sounds good!","TWN":"嘿嘿，那好唄！"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"마, 박스! 니 분명, 니 입으로 그랬다 아이가.","JPN":"おい、ダンボール！　あんた確かに自分の口でこう言うたよな？","ENG":"You, Box! Ya said it yourself, didn’t ya?","TWN":"喂，紙箱！不是你說的嗎！"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"우리가 만든 게임은 사람들을 실망시킬 거라고……","JPN":"ウチらが作ったゲームに、みんながガッカリするて……","ENG":"That our game will disappoint the fans...","TWN":"我們做的遊戲會讓玩家失望……"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그리고 스트리트 카운터는 니한테 무척 소중한 게임이라고……!","JPN":"そしてストリート・カウンターは、あんたにとってとっても大事なゲームやって……！","ENG":"And that Street Counter is somethin’ dear to ya!","TWN":"還說什麼你很熱愛街頭制裁者……！"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼 우리 연구회에 들어와서 니 스스로 직접 게임을 바꾸는기다!","JPN":"じゃあ、うちの研究会に入って自分の手でゲームを変えるんや！","ENG":"So come join our club, and you can make the game better!","TWN":"那你就加入我們研究社，自己親手改變遊戲吧！"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...Huh?","TWN":"……什麼？"},"stage":{"bg":"COMICFESTIVAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};